from flask import Flask, redirect, request, session, url_for, jsonify
from urllib.parse import urlencode
import os
import secrets

app = Flask(__name__)
app.secret_key = os.environ.get("FLASK_SECRET_KEY", secrets.token_hex(32))

OIDC_ISSUER = os.environ.get("OIDC_ISSUER", "https://example.com")
AUTHORIZATION_ENDPOINT = os.environ.get("OIDC_AUTHORIZATION_ENDPOINT", f"{OIDC_ISSUER}/authorize")
CLIENT_ID = os.environ.get("OIDC_CLIENT_ID", "your-client-id")
REDIRECT_URI = os.environ.get("OIDC_REDIRECT_URI", "http://localhost:5000/callback")
SCOPE = "openid"


@app.route("/")
def index():
    if session.get("authenticated"):
        return jsonify(
            {
                "authenticated": True,
                "id_token": session.get("id_token"),
                "state": session.get("state"),
            }
        )
    return '<a href="/login">Login with OpenID Connect</a>'


@app.route("/login")
def login():
    state = secrets.token_urlsafe(32)
    session["state"] = state

    params = {
        "client_id": CLIENT_ID,
        "redirect_uri": REDIRECT_URI,
        "scope": SCOPE,
        "response_type": "id_token",
        "state": state,
    }

    return redirect(f"{AUTHORIZATION_ENDPOINT}?{urlencode(params)}")


@app.route("/callback")
def callback():
    returned_state = request.args.get("state")
    id_token = request.args.get("id_token")

    if not returned_state or returned_state != session.get("state"):
        return jsonify({"error": "invalid_state"}), 400

    if not id_token:
        return jsonify(
            {
                "error": "missing_id_token",
                "details": "For response_type=id_token, many providers return tokens in the URL fragment. Consider handling it client-side and POSTing it to the server.",
            }
        ), 400

    session["authenticated"] = True
    session["id_token"] = id_token
    return redirect(url_for("index"))


@app.route("/logout")
def logout():
    session.clear()
    return redirect(url_for("index"))


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.environ.get("PORT", "5000")), debug=True)